1469→            timeout_explore: Some(Duration::from_millis(1)),
1470→            ..Default::default()
1471→        };
1472→
1473→        let seeds = (0..100)
1474→            .map(|i| vec![serde_json::json!(i)])
1475→            .collect();
1476→
1477→        let result = explore(
1478→            &mut frontend,
1479→            "stub",
1480→            seeds,
1481→            vec![],
1482→            &[ParamInfo { name: "x".into(), typ: crate::types::TypeInfo::Int, type_name: None }],
1483→            &explore_config,
1484→        )
1485→        .await
1486→        .expect("explore failed");
1487→
1488→        // Should terminate due to timeout, not max_executions or max_iterations.
1489→        assert_eq!(result.termination_reason, TerminationReason::TimeoutExplore);
1490→        assert!(result.total_executions < 10000);
1491→
1492→        frontend.shutdown().await.expect("shutdown failed");
1493→    }
1494→
1495→    /// Triage should skip redundant inputs that predict already-covered paths.
1496→    ///
1497→    /// Uses a fixed-branch frontend (always returns same single-branch path).
1498→    /// After the first seed discovers the path, triage predicts Skip for
1499→    /// all subsequent seeds with matching constraint evaluations.
1500→    #[tokio::test]
1501→    async fn explore_triage_skips_redundant_seeds() {
1502→        let config = config_for_script("fixed-branch-frontend.sh");
1503→        let mut frontend = Frontend::spawn(&config).await.expect("spawn failed");
1504→
1505→        let explore_config = ExploreConfig {
1506→            max_iterations: 50,
1507→            max_executions: 50,
1508→            plateau_threshold: 0, // disable plateau so we rely on worklist exhaustion
1509→            ..Default::default()
1510→        };
1511→
1512→        // All seeds have x=5, which evaluates x>0 to true (Taken) — matching
1513→        // the path discovered by the first execution. After the first seed
1514→        // discovers the path and updates triage, subsequent seeds predict the
1515→        // same covered path → Skip.
1516→        let seeds: Vec<Vec<serde_json::Value>> = (0..20)
1517→            .map(|_| vec![serde_json::json!(5)])
1518→            .collect();
1519→
1520→        let result = explore(
1521→            &mut frontend,
1522→            "f",
1523→            seeds,
1524→            vec![],
1525→            &[ParamInfo { name: "x".into(), typ: crate::types::TypeInfo::Int, type_name: None }],
1526→            &explore_config,
1527→        )
1528→        .await
1529→        .expect("explore failed");
1530→
1531→        assert!(
1532→            result.triage_skipped > 0,
1533→            "expected triage to skip redundant inputs, but triage_skipped={}",
1534→            result.triage_skipped
1535→        );
1536→        assert_eq!(result.unique_paths, 1);
1537→
1538→        frontend.shutdown().await.expect("shutdown failed");
1539→    }
1540→
1541→    // -----------------------------------------------------------------------
1542→    // Property-based tests
1543→    // -----------------------------------------------------------------------
1544→
1545→    mod prop_tests {
1546→        use super::*;
1547→        use crate::solver::ConcreteValue;
1548→        use crate::test_arbitraries::{arb_input_source, arb_json_value, arb_sym_expr};
1549→        use proptest::prelude::*;
1550→
1551→        proptest! {
1552→            #[test]
1553→            fn overlay_preserves_length(
1554→                len in 1..6usize,
1555→            ) {
1556→                let base: Vec<serde_json::Value> =
1557→                    (0..len).map(|i| serde_json::json!(i as i64)).collect();
1558→                let names: Vec<String> =
1559→                    (0..len).map(|i| format!("p{i}")).collect();
1560→                // Empty solved map — output must equal input length.
1561→                let solved = std::collections::HashMap::new();
1562→                let result = overlay_solved_values(&base, &solved, &names);
1563→                prop_assert_eq!(
1564→                    base.len(),
1565→                    result.len(),
1566→                    "overlay_solved_values changed vector length"
1567→                );
1568→            }
1569→
1570→            #[test]
1571→            fn overlay_with_known_param_updates_value(idx in 0..5usize) {
1572→                let len = idx + 1;
1573→                let base: Vec<serde_json::Value> =
1574→                    (0..len).map(|i| serde_json::json!(i as i64)).collect();
1575→                let names: Vec<String> =
1576→                    (0..len).map(|i| format!("p{i}")).collect();
1577→                let mut solved = std::collections::HashMap::new();
1578→                solved.insert(format!("p{idx}"), ConcreteValue::Int(999));
1579→                let result = overlay_solved_values(&base, &solved, &names);
1580→                prop_assert_eq!(result.len(), base.len());
1581→                prop_assert_eq!(&result[idx], &serde_json::json!(999));
1582→            }
1583→
1584→            #[test]
1585→            fn overlay_ignores_unknown_names(
1586→                base_val in arb_json_value(),
1587→            ) {
1588→                let base = vec![base_val.clone()];
1589→                let names = vec!["x".to_string()];
1590→                let mut solved = std::collections::HashMap::new();
1591→                // "unknown_var" doesn't match "x", so base should be unchanged.
1592→                // Exception: single-param heuristic fires for non-dotted names,
1593→                // so use a dotted name to avoid that path.
1594→                solved.insert("unknown.derived".to_string(), ConcreteValue::Int(42));
1595→                let result = overlay_solved_values(&base, &solved, &names);
1596→                prop_assert_eq!(result.len(), 1);
1597→                prop_assert_eq!(&result[0], &base_val);
1598→            }
1599→
1600→            /// Worklist dequeues entries in non-increasing InputSource priority.
1601→            #[test]
1602→            fn worklist_dequeues_in_priority_order(
1603→                sources in prop::collection::vec(arb_input_source(), 1..20),
1604→            ) {
1605→                let mut heap = BinaryHeap::new();
1606→                for source in &sources {
1607→                    heap.push(WorklistEntry {
1608→                        inputs: vec![],
1609→                        source: *source,
1610→                    });
1611→                }
1612→                let drained: Vec<InputSource> = std::iter::from_fn(|| heap.pop())
1613→                    .map(|e| e.source)
1614→                    .collect();
1615→                // Each element must be >= the next (non-increasing order).
1616→                for window in drained.windows(2) {
1617→                    prop_assert!(
1618→                        window[0] >= window[1],
1619→                        "worklist violated priority order: {:?} before {:?}",
1620→                        window[0], window[1]
1621→                    );
1622→                }
1623→                prop_assert_eq!(drained.len(), sources.len());
1624→            }
1625→
1626→            /// Inserting duplicate path hashes into covered_paths is idempotent.
1627→            #[test]
1628→            fn path_dedup_set_size_equals_distinct_count(
1629→                hashes in prop::collection::vec(0..100u64, 1..50),
1630→            ) {
1631→                let mut covered = HashSet::new();
1632→                for &h in &hashes {
1633→                    covered.insert(h);
1634→                }
1635→                let distinct: HashSet<u64> = hashes.iter().copied().collect();
1636→                prop_assert_eq!(covered.len(), distinct.len());
1637→                // Second insert of every element returns false.
1638→                for &h in &hashes {
1639→                    prop_assert!(!covered.insert(h), "re-insert of {h} should return false");
1640→                }
1641→                prop_assert_eq!(covered.len(), distinct.len(), "size changed after re-inserts");
1642→            }
1643→
1644→            /// Budget exhaustion: a loop bounded by max_executions terminates
1645→            /// after exactly min(max_executions, worklist_size) iterations.
1646→            #[test]
1647→            fn budget_limits_iteration_count(
1648→                max_executions in 1..200usize,
1649→                worklist_size in 1..500usize,
1650→            ) {
1651→                let mut worklist = BinaryHeap::new();
1652→                for _ in 0..worklist_size {
1653→                    worklist.push(WorklistEntry {
1654→                        inputs: vec![],
1655→                        source: InputSource::Seed,
1656→                    });
1657→                }
1658→                let mut executed = 0usize;
1659→                while let Some(_entry) = worklist.pop() {
1660→                    executed += 1;
1661→                    if executed >= max_executions {
1662→                        break;
1663→                    }
1664→                }
1665→                let expected = max_executions.min(worklist_size);
1666→                prop_assert_eq!(executed, expected);
1667→            }
1668→
1669→            /// Constraint accumulation grows monotonically — no constraints lost.
1670→            #[test]
1671→            fn constraint_accumulation_is_monotonic(
1672→                batches in prop::collection::vec(
1673→                    prop::collection::vec(
1674→                        proptest::option::of(arb_sym_expr(1)),
1675→                        0..5
1676→                    ),
1677→                    1..10
1678→                ),
1679→            ) {
1680→                let mut all_constraints: Vec<Vec<Option<SymExpr>>> = Vec::new();
1681→                for batch in &batches {
1682→                    all_constraints.push(batch.clone());
1683→                    prop_assert_eq!(
1684→                        all_constraints.len(),
1685→                        all_constraints.len(), // tautology for the assertion below
1686→                    );
1687→                }
1688→                // Length equals number of batches — nothing was dropped.
1689→                prop_assert_eq!(all_constraints.len(), batches.len());
1690→                // Each entry matches its source batch.
1691→                for (i, batch) in batches.iter().enumerate() {
1692→                    prop_assert_eq!(&all_constraints[i], batch);
1693→                }
1694→            }
1695→        }
1696→    }
1697→}
1698→

