                    total_probes += 1;

                    if crate::float_probe::executions_agree(float_result, floor_result) {
                        agreements += 1;
                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
                        divergent_values.push(v);
                    }
                }
