1084→                    other => panic!("expected Int for x, got {other:?}"),
1085→                };
1086→                assert_eq!(x, 42, "negating NOT(x==42) should yield x=42");
1087→            }
1088→            SolveResult::Unsat => panic!("expected sat"),
1089→        }
