355→/// Run the concolic exploration loop on a function via a frontend subprocess.
356→///
357→/// `function_name` is the fully-qualified name of the function to explore.
358→/// `seed_inputs` provides initial input sets to begin exploration.
359→/// `user_inputs` provides user-provided candidate inputs (highest priority).
360→/// `param_infos` provides parameter metadata including names and types. Names are
361→/// used to map Z3 variables back to parameter positions; types are used to declare
362→/// correct Z3 sorts (preventing string params from being declared as Int).
363→pub async fn explore(
364→    frontend: &mut Frontend,
365→    function_name: &str,
366→    seed_inputs: Vec<Vec<serde_json::Value>>,
367→    user_inputs: Vec<Vec<serde_json::Value>>,
368→    param_infos: &[ParamInfo],
369→    config: &ExploreConfig,
370→) -> Result<ExploreResult, ExploreError> {
371→    let param_names: Vec<String> = param_infos.iter().map(|p| p.name.clone()).collect();
372→    let mut worklist = BinaryHeap::new();
373→    let mut covered_paths: HashSet<u64> = HashSet::new();
374→    let mut executions = Vec::new();
375→    let mut raw_results: Vec<(Vec<serde_json::Value>, ExecuteResult)> = Vec::new();
376→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
377→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
378→    let mut total_executions: usize = 0;
379→    let mut z3_generated: usize = 0;
380→    let mut fuzz_generated: usize = 0;
381→    let mut drill_generated: usize = 0;
382→    let mut plateau_counter: usize = 0;
383→    let mut termination_reason = TerminationReason::WorklistExhausted;
384→    let mut seen_branch_sides: HashSet<(u32, bool)> = HashSet::new();
385→    let mut frontier_set = FrontierSet::new();
386→    let mut rng = StdRng::from_os_rng();
387→    let mut triage_state = TriageState::new(param_names.clone());
388→    let mut triage_skipped: usize = 0;
389→    let mut triage_mispredictions: usize = 0;
390→
391→    // Add user-provided candidates with highest priority.
392→    for inputs in user_inputs {
393→        worklist.push(WorklistEntry {
394→            inputs,
395→            source: InputSource::UserProvided,
396→        });
397→    }
398→
399→    // Seed the worklist.
400→    for inputs in seed_inputs {
401→        worklist.push(WorklistEntry {
402→            inputs,
403→            source: InputSource::Seed,
404→        });
405→    }
406→
407→    // --- Float probe phase ---
408→    let float_indices = crate::float_probe::float_param_indices(param_infos);
409→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
410→    if !float_indices.is_empty() {
411→        for &idx in &float_indices {
412→            let pairs = crate::float_probe::generate_probe_pairs(
413→                param_infos,
414→                idx,
415→                crate::float_probe::PROBE_COUNT,
416→                &mut rng,
417→            );
418→            let mut agreements = 0usize;
419→            let mut total_probes = 0usize;
420→            let mut divergent_values = Vec::new();
421→
422→            for (float_inputs, floor_inputs) in pairs {
423→                // Execute with float value.
424→                let float_resp = frontend
425→                    .send(Command::Execute {
426→                        function: function_name.to_string(),
427→                        inputs: float_inputs.clone(),
428→                        mocks: config.mocks.clone(),
429→                        setup_context: None,
430→                    })
431→                    .await?;
432→
433→                // Execute with floor value.
434→                let floor_resp = frontend
435→                    .send(Command::Execute {
436→                        function: function_name.to_string(),
437→                        inputs: floor_inputs,
438→                        mocks: config.mocks.clone(),
439→                        setup_context: None,
440→                    })
441→                    .await?;
442→
443→                if let (
444→                    ResponseResult::Execute(float_result),
445→                    ResponseResult::Execute(floor_result),
446→                ) = (&float_resp.result, &floor_resp.result) {
447→                    total_probes += 1;
448→
449→                    if crate::float_probe::executions_agree(float_result, floor_result) {
450→                        agreements += 1;
451→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
452→                        divergent_values.push(v);
453→                    }
454→                }
455→            }
456→
457→            let classification = crate::float_probe::classify(
458→                agreements,
459→                total_probes,
460→                crate::float_probe::AGREEMENT_THRESHOLD,
461→            );
462→            float_probe_results.push(crate::float_probe::FloatProbeResult {
463→                param_index: idx,
464→                param_name: param_infos[idx].name.clone(),
465→                classification,
466→                agreements,
467→                total_probes,
468→                divergent_values,
469→            });
470→        }
471→    }
472→
473→    let explore_start = Instant::now();
474→
475→    while let Some(entry) = worklist.pop() {
476→        if executions.len() >= config.max_iterations {
477→            termination_reason = TerminationReason::MaxIterations;
478→            break;
479→        }
480→        if total_executions >= config.max_executions {
481→            termination_reason = TerminationReason::MaxExecutions;
482→            break;
483→        }
484→        if let Some(timeout) = config.timeout_explore
485→            && explore_start.elapsed() >= timeout
486→        {
487→            termination_reason = TerminationReason::TimeoutExplore;
488→            break;
489→        }
490→        if config.plateau_threshold > 0 && plateau_counter >= config.plateau_threshold {
491→            termination_reason = TerminationReason::CoveragePlateau;
492→            break;
493→        }
494→
495→        // Triage: predict whether this input will produce a novel path.
496→        // Skip triage for user-provided inputs — always execute those.
497→        let is_sampled_skip = if entry.source != InputSource::UserProvided {
498→            let verdict = triage_state.triage_candidate(&entry.inputs, &covered_paths);
499→            triage_state.record_verdict(&verdict);
500→            if verdict == TriageVerdict::Skip {
501→                if triage_state.should_sample() {
502→                    // Execute anyway to validate the prediction.
503→                    true
504→                } else {
505→                    triage_skipped += 1;
506→                    continue;
507→                }
508→            } else {
509→                false
510→            }
511→        } else {
512→            false
513→        };
514→
515→        // Execute concretely via the frontend.
516→        let response = frontend
517→            .send(Command::Execute {
518→                function: function_name.to_string(),
519→                inputs: entry.inputs.clone(),
520→                mocks: config.mocks.clone(),
521→                setup_context: None,
522→            })
523→            .await?;
524→
525→        total_executions += 1;
526→
