        if unique_path_count + observations.iter().filter(|o: &&Observation| o.is_new_path).count()
            >= config.max_iterations
        {
            return Ok((observations, round_executions, round_triage_skipped, round_triage_mispredictions, Some(TerminationReason::MaxIterations)));
        }
        if total_executions_so_far + round_executions >= config.max_executions {
            return Ok((observations, round_executions, round_triage_skipped, round_triage_mispredictions, Some(TerminationReason::MaxExecutions)));
        }
        if let Some(timeout) = config.timeout_explore
            && explore_start.elapsed() >= timeout
        {
            return Ok((observations, round_executions, round_triage_skipped, round_triage_mispredictions, Some(TerminationReason::TimeoutExplore)));
        }
        if config.plateau_threshold > 0 && *plateau_counter >= config.plateau_threshold {
            return Ok((observations, round_executions, round_triage_skipped, round_triage_mispredictions, Some(TerminationReason::CoveragePlateau)));
        }

        // Triage: predict whether this input will produce a novel path.
        let is_sampled_skip = if entry.source != InputSource::UserProvided {
            let verdict = triage_state.triage_candidate(&entry.inputs, covered_paths);
            triage_state.record_verdict(&verdict);
            if verdict == TriageVerdict::Skip {
                if triage_state.should_sample() {
                    true
                } else {
                    round_triage_skipped += 1;
                    continue;
                }
            } else {
                false
            }
        } else {
            false
        };

        // Execute concretely via the frontend.
        let response = frontend
            .send(Command::Execute {
                function: function_name.to_string(),
                inputs: entry.inputs.clone(),
                mocks: config.mocks.clone(),
                setup_context: None,
            })
            .await?;

        round_executions += 1;

        let exec_result = match response.result {
            ResponseResult::Execute(result) => *result,
            ResponseResult::Error { message, .. } => {
                log::warn!("frontend error during execute: {message}");
                continue;
            }
            _ => continue,
        };

        let path_id = hash_branch_path(&exec_result.branch_path);

        // Validate sampled skip prediction before modifying covered_paths.
        if is_sampled_skip {
            let already_covered = covered_paths.contains(&path_id);
            triage_state.record_sample(0, if already_covered { 0 } else { 1 });
            if !already_covered {
                round_triage_mispredictions += 1;
            }
        }

        let is_new_path = covered_paths.insert(path_id);
        if !is_new_path {
            *plateau_counter += 1;
        } else {
            *plateau_counter = 0;
            triage_state.update(&exec_result.branch_path);
        }

        observations.push(Observation {
            inputs: entry.inputs,
            result: exec_result,
            source: entry.source,
            path_id,
            is_new_path,
            is_sampled_skip,
        });
    }

    Ok((observations, round_executions, round_triage_skipped, round_triage_mispredictions, None))
}

