        frontend,
        function_name,
        config,
        &mut observe_state,
        executions.len(),
        total_executions,
        explore_start,
    )
    .await?;

    total_executions += round.executions;
    triage_skipped += round.triage_skipped;
    triage_mispredictions += round.triage_mispredictions;

