    /// Request timeout for integration tests using mock frontends.
    const TEST_REQUEST_TIMEOUT: Duration = Duration::from_secs(10);

    fn frontend_script(name: &str) -> PathBuf {
        let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
