377→/// Execute a single observe round: drain the worklist, execute each entry via the
378→/// frontend, and return classified observations.
379→///
380→/// Respects budget limits (max_iterations, max_executions, timeout, plateau).
381→/// If a termination condition fires mid-round, the reason is returned and the
382→/// caller should stop after processing the observations collected so far.
383→async fn observe_round(
384→    worklist: &mut BinaryHeap<WorklistEntry>,
385→    frontend: &mut Frontend,
386→    function_name: &str,
387→    config: &ExploreConfig,
388→    state: &mut ObserveState,
389→) -> Result<ObserveRoundOutput, ExploreError> {
390→    let mut out = ObserveRoundOutput {
391→        observations: Vec::new(),
392→        executions: 0,
393→        triage_skipped: 0,
394→        triage_mispredictions: 0,
395→        termination: None,
396→    };
397→
398→    while let Some(entry) = worklist.pop() {
399→        // Check termination budgets.
400→        let new_paths_this_round = out.observations.iter().filter(|o| o.is_new_path).count();
401→        if state.unique_path_count + new_paths_this_round >= config.max_iterations {
402→            out.termination = Some(TerminationReason::MaxIterations);
403→            return Ok(out);
404→        }
405→        if state.total_executions + out.executions >= config.max_executions {
406→            out.termination = Some(TerminationReason::MaxExecutions);
407→            return Ok(out);
408→        }
409→        if let Some(timeout) = config.timeout_explore
410→            && state.explore_start.elapsed() >= timeout
411→        {
412→            out.termination = Some(TerminationReason::TimeoutExplore);
413→            return Ok(out);
414→        }
415→        if config.plateau_threshold > 0 && state.plateau_counter >= config.plateau_threshold {
416→            out.termination = Some(TerminationReason::CoveragePlateau);
417→            return Ok(out);
418→        }
419→
420→        // Triage: predict whether this input will produce a novel path.
421→        let is_sampled_skip = if entry.source != InputSource::UserProvided {
422→            let verdict = state
