/// Mutable state shared between the observe and main loop phases.
struct ObserveState {
    covered_paths: HashSet<u64>,
    triage_state: TriageState,
    plateau_counter: usize,
    /// How many unique paths have been recorded so far (for budget checks).
    unique_path_count: usize,
    /// How many total executions have been performed so far (for budget checks).
    total_executions: usize,
    /// Wall-clock start time for timeout checks.
    explore_start: Instant,
}

/// Counters returned from an observe round to update the main loop accumulators.
struct ObserveRoundOutput {
    observations: Vec<Observation>,
    executions: usize,
    triage_skipped: usize,
    triage_mispredictions: usize,
    termination: Option<TerminationReason>,
}

/// Execute a single observe round: drain the worklist, execute each entry via the
/// frontend, and return classified observations.
///
/// Respects budget limits (max_iterations, max_executions, timeout, plateau).
/// If a termination condition fires mid-round, the reason is returned and the
/// caller should stop after processing the observations collected so far.
async fn observe_round(
    worklist: &mut BinaryHeap<WorklistEntry>,
    frontend: &mut Frontend,
    function_name: &str,
    config: &ExploreConfig,
    state: &mut ObserveState,
) -> Result<ObserveRoundOutput, ExploreError> {
    let mut out = ObserveRoundOutput {
        observations: Vec::new(),
        executions: 0,
        triage_skipped: 0,
        triage_mispredictions: 0,
        termination: None,
    };

    while let Some(entry) = worklist.pop() {
        // Check termination budgets.
        let new_paths_this_round = out.observations.iter().filter(|o| o.is_new_path).count();
        if state.unique_path_count + new_paths_this_round >= config.max_iterations {
            out.termination = Some(TerminationReason::MaxIterations);
            return Ok(out);
        }
        if state.total_executions + out.executions >= config.max_executions {
            out.termination = Some(TerminationReason::MaxExecutions);
            return Ok(out);
        }
        if let Some(timeout) = config.timeout_explore
            && state.explore_start.elapsed() >= timeout
        {
            out.termination = Some(TerminationReason::TimeoutExplore);
            return Ok(out);
        }
        if config.plateau_threshold > 0 && state.plateau_counter >= config.plateau_threshold {
            out.termination = Some(TerminationReason::CoveragePlateau);
            return Ok(out);
        }

        // Triage: predict whether this input will produce a novel path.
        let is_sampled_skip = if entry.source != InputSource::UserProvided {
            let verdict = state
                .triage_state
                .triage_candidate(&entry.inputs, &state.covered_paths);
            state.triage_state.record_verdict(&verdict);
            if verdict == TriageVerdict::Skip {
                if state.triage_state.should_sample() {
                    true
                } else {
                    out.triage_skipped += 1;
                    continue;
                }
            } else {
                false
            }
        } else {
            false
        };

        // Execute concretely via the frontend.
        let response = frontend
            .send(Command::Execute {
                function: function_name.to_string(),
                inputs: entry.inputs.clone(),
                mocks: config.mocks.clone(),
                setup_context: None,
            })
            .await?;

        out.executions += 1;

        let exec_result = match response.result {
            ResponseResult::Execute(result) => *result,
            ResponseResult::Error { message, .. } => {
                log::warn!("frontend error during execute: {message}");
                continue;
            }
            _ => continue,
        };

        let path_id = hash_branch_path(&exec_result.branch_path);

        // Validate sampled skip prediction before modifying covered_paths.
        if is_sampled_skip {
            let already_covered = state.covered_paths.contains(&path_id);
            state
                .triage_state
                .record_sample(0, if already_covered { 0 } else { 1 });
            if !already_covered {
                out.triage_mispredictions += 1;
            }
        }

        let is_new_path = state.covered_paths.insert(path_id);

