        let path = vec![
            BranchDecision {
                branch_id: 0,
                line: 10,
                taken: true,
                constraint: SymConstraint::Unknown {
                    hint: "x".into(),
                },
            },
            BranchDecision {
                branch_id: 1,
                line: 20,
                taken: false,
                constraint: SymConstraint::Unknown {
                    hint: "y".into(),
                },
            },
        ];
        assert_eq!(hash_branch_path(&path), hash_branch_path(&path));
    }

