            constraint: SymConstraint::Unknown {
                hint: "x".into(),
            },
        }];
        let path_b = vec![BranchDecision {
            branch_id: 0,
            line: 10,
            taken: false,
            constraint: SymConstraint::Unknown {
                hint: "x".into(),
            },
        }];
        assert_ne!(hash_branch_path(&path_a), hash_branch_path(&path_b));
    }

